const cfg = $('Trigger').first().json.config || {};
const orderRaw = cfg.discovery_fetcher_order || '';
const enabledSources = String(orderRaw)
  .split(/[;,]/)
  .map(s => s.trim().toLowerCase())
  .filter(s => s.length > 0);

if (!enabledSources.includes('jsearch')) {
  console.log('[JSearch] Disabled via discovery_fetcher_order â€” skipping');
  return [];
}
const stripEquals = (v) => (typeof v === 'string' && v.startsWith('=')) ? v.substring(1) : v;
const config = $('Trigger').first().json.config || {};

const parseList = (val) => {
  if (!val) return [];
  return String(val).split(/[;,]/).map(s => s.trim()).filter(Boolean);
};

const targetTitles = parseList(stripEquals(config.target_titles));
if (targetTitles.length === 0) {
  throw new Error('[JSearch Source] No target_titles configured');
}

const country = String(stripEquals(config.target_country) || 'us').toLowerCase();

const windowHours = Number(stripEquals(config.search_window_hours)) || 0;
let datePosted = 'all';
if (windowHours > 0 && windowHours <= 24) datePosted = 'today';
else if (windowHours > 0 && windowHours <= 72) datePosted = '3days';
else if (windowHours > 0 && windowHours <= 168) datePosted = 'week';
else if (windowHours > 0 && windowHours <= 720) datePosted = 'month';

const employmentTypeMap = {
  full_time: 'FULLTIME',
  part_time: 'PARTTIME',
  contract: 'CONTRACTOR',
  internship: 'INTERN'
  // temporary not supported by JSearch â€” silently dropped
};
const employmentTypes = parseList(stripEquals(config.employment_type_considered))
  .map(t => employmentTypeMap[t])
  .filter(Boolean);

// Results-per-query â†’ JSearch pages. JSearch returns ~10 results/page.
// pages = ceil(desired / 10), e.g. 84 -> 9. Default 10 results (1 page) if unset.
// The page ceiling is config-driven (discovery_max_pages_per_query) so the user
// can raise it after buying RapidAPI credits â€” no hardcoded limit.
const desiredResults = Number(stripEquals(config.discovery_max_results_per_query)) || 10;
const PAGE_SIZE = 10;

let pagesPerQuery = Math.ceil(desiredResults / PAGE_SIZE);
if (!Number.isFinite(pagesPerQuery) || pagesPerQuery < 1) pagesPerQuery = 1;

const maxPagesRaw = Number(stripEquals(config.discovery_max_pages_per_query));
const maxPages = (Number.isFinite(maxPagesRaw) && maxPagesRaw >= 1) ? Math.floor(maxPagesRaw) : null;
if (maxPages !== null && pagesPerQuery > maxPages) {
  console.log(`[JSearch Build Queries] pages ${pagesPerQuery} clamped to ceiling ${maxPages} (discovery_max_pages_per_query)`);
  pagesPerQuery = maxPages;
}

// num_pages pulls N pages in ONE API call per title (cheaper on the call budget).
const items = [];
for (const title of targetTitles) {
  items.push({
    json: {
      query: title,
      page: '1',
      num_pages: String(pagesPerQuery),
      country,
      date_posted: datePosted,
      employment_types: employmentTypes
    }
  });
}

console.log(`[JSearch Build Queries] ${targetTitles.length} titles Ã— ${pagesPerQuery} pages (desired ${desiredResults} results/query${maxPages !== null ? `, ceiling ${maxPages}` : ', no ceiling'}) = ${items.length} API calls, date_posted=${datePosted}`);

return items;

// JSearch: parse + normalize. With "Include Response Headers and Status" ON,
// the HTTP node wraps the payload as { body, headers, statusCode }.
const envelope = $input.item.json;
const response = (envelope && envelope.body) ? envelope.body : envelope; // tolerate both shapes
const data = Array.isArray(response.data) ? response.data : [];
if (response.status && response.status !== 'OK') {
  console.log(`[JSearch Parse] Non-OK status: ${response.status}, skipping`);
  return [];
}
const buildLocation = (job) => {
  const parts = [];
  if (job.job_city) parts.push(job.job_city);
  if (job.job_state) parts.push(job.job_state);
  if (job.job_country) parts.push(job.job_country);
  if (parts.length === 0 && job.job_is_remote) return 'Remote';
  return parts.join(', ');
};
const buildSalaryText = (job) => {
  const min = job.job_min_salary;
  const max = job.job_max_salary;
  const currency = job.job_salary_currency || 'USD';
  const period = (job.job_salary_period || '').toLowerCase();
  if (!min && !max) return '';
  const fmt = (n) => n ? `${currency} ${Math.round(n).toLocaleString()}` : '';
  if (min && max) return `${fmt(min)} - ${fmt(max)}${period ? ' / ' + period : ''}`;
  return `${fmt(min || max)}${period ? ' / ' + period : ''}`;
};
const normalized = data.map(job => ({
  company: String(job.employer_name || '').trim(),
  title: String(job.job_title || '').trim(),
  url: String(job.job_apply_link || '').trim(),
  description_html: '',
  description: String(job.job_description || '').trim(),
  location: buildLocation(job),
  remote: job.job_is_remote === true,
  salary_text: buildSalaryText(job),
  employment_type: String((Array.isArray(job.job_employment_types) && job.job_employment_types[0]) || '').toUpperCase().trim(),
  source: 'jsearch',
  posted_at: job.job_posted_at_datetime_utc || ''
}));
const queryName = response.parameters?.query || '?';
console.log(`[JSearch Parse] Query "${queryName}": ${data.length} raw, ${normalized.length} normalized`);
return normalized.map(j => ({ json: j }));

// JSearch usage â€” read the gateway's actual remaining quota from response headers,
// not an inferred call count. Runs on the API success output (one item per call);
// each item carries headers from its own call. Quota is monotonic-decreasing within
// a run, so the lowest remaining = the truest post-run figure. Reset seconds also
// monotonically decreases during the run (countdown to window rollover), so MIN
// is again the freshest snapshot.
const items = $input.all();
const runId = $('Trigger').first().json.run_id || '';

const headerVal = (h, name) => {
  if (!h) return null;
  // header keys can vary in case
  const key = Object.keys(h).find(k => k.toLowerCase() === name.toLowerCase());
  if (!key) return null;
  const n = Number(h[key]);
  return Number.isFinite(n) ? n : null;
};

let remaining = null;
let limit = null;
let resetSeconds = null;
let successfulCalls = 0;

for (const it of items) {
  const env = it.json || {};
  const headers = env.headers || {};
  const status = env.statusCode;
  if (status === undefined || (status >= 200 && status < 300)) successfulCalls++;

  const rem = headerVal(headers, 'x-ratelimit-requests-remaining');
  if (rem !== null) remaining = (remaining === null) ? rem : Math.min(remaining, rem);

  const lim = headerVal(headers, 'x-ratelimit-requests-limit');
  if (lim !== null) limit = lim;

  const rst = headerVal(headers, 'x-ratelimit-requests-reset');
  if (rst !== null) resetSeconds = (resetSeconds === null) ? rst : Math.min(resetSeconds, rst);
}

console.log(`[JSearch Usage] run=${runId} successful_calls=${successfulCalls} quota_remaining=${remaining} quota_limit=${limit} quota_reset_seconds=${resetSeconds}`);

return [{
  json: {
    _type: 'usage',
    run_id: runId,
    timestamp: new Date().toISOString(),
    source: 'jsearch',
    successful_calls: successfulCalls,
    quota_remaining: remaining,       // ground truth from gateway header; null if header absent
    quota_limit: limit,
    quota_reset_seconds: resetSeconds // seconds until quota window rollover; null if header absent
  }
}];

const runId = $('Trigger').first().json.run_id || '';
const errPayload = $input.first().json || {};
const errObj = errPayload.error || {};

// Original query that failed â€” paired-item access to Build Queries input
let query = '';
try {
  const q = $('Build Queries').item.json || {};
  query = String(q.query || '');
} catch (e) {
  query = '';
}

const statusCode = String(
  errObj.httpCode ||
  errObj.status ||
  errObj.cause?.response?.status ||
  ''
);
const message = String(errObj.message || 'Unknown error').substring(0, 500);

console.log(`[JSearch] Fetch failed for query="${query}": ${statusCode} ${message}`);

return [{
  json: {
    _type: 'failure',
    run_id: runId,
    discovered_at: new Date().toISOString(),
    source: 'jsearch',
    company: '',
    slug: '',
    query: query,
    status_code: statusCode,
    error_message: message
  }
}];
